/**
 * Wire-nav step — resolves each entity's `memberCountryIso31661Alpha2Codes`
 * via `CountryLookup` and populates `memberCountries`.
 */
export function wireGeopoliticalEntityNav(): void {
  for (const entity of GeopoliticalEntityLookup.all) {
    const mut = entity as { -readonly [K in keyof GeopoliticalEntity]: GeopoliticalEntity[K] };
    const list: Country[] = [];
    for (const cc of entity.memberCountryIso31661Alpha2Codes) {
      const country = CountryLookup.byCode[cc];
      if (country !== undefined) list.push(country);
    }
    mut.memberCountries = list;
  }
}
